 64→public final class StoreQueryUtils {
 65→
 66→    /**
 67→     * a utility interface to facilitate stores' query dispatch logic,
 68→     * allowing them to generically store query execution logic as the values
 69→     * in a map.
 70→     */
 71→    @FunctionalInterface
 72→    public interface QueryHandler {
 73→        QueryResult<?> apply(
 74→            final Query<?> query,
 75→            final PositionBound positionBound,
 76→            final QueryConfig config,
 77→            final StateStore store
 78→        );
 79→    }
 80→
 81→    @SuppressWarnings("rawtypes")
 82→    private static final Map<Class, QueryHandler> QUERY_HANDLER_MAP =
 83→        mkMap(
 84→            mkEntry(
 85→                RangeQuery.class,
 86→                StoreQueryUtils::runRangeQuery
 87→            ),
 88→            mkEntry(
 89→                KeyQuery.class,
 90→                StoreQueryUtils::runKeyQuery
 91→            ),
 92→            mkEntry(
 93→                WindowKeyQuery.class,
 94→                StoreQueryUtils::runWindowKeyQuery
 95→            ),
 96→            mkEntry(
 97→                WindowRangeQuery.class,
 98→                StoreQueryUtils::runWindowRangeQuery
 99→            ),
100→            mkEntry(
101→                VersionedKeyQuery.class,
102→                StoreQueryUtils::runVersionedKeyQuery
103→            ),
104→            mkEntry(
105→                MultiVersionedKeyQuery.class,
106→                StoreQueryUtils::runMultiVersionedKeyQuery
107→            )
108→        );
109→
110→    // make this class uninstantiable
111→
112→    private StoreQueryUtils() {
113→    }
114→    @SuppressWarnings("unchecked")
115→    public static <R> QueryResult<R> handleBasicQueries(
116→        final Query<R> query,
117→        final PositionBound positionBound,
118→        final QueryConfig config,
119→        final StateStore store,
120→        final Position position,
121→        final StateStoreContext context
122→    ) {
123→
124→        final long start = config.isCollectExecutionInfo() ? System.nanoTime() : -1L;
125→        final QueryResult<R> result;
126→
127→        final QueryHandler handler = QUERY_HANDLER_MAP.get(query.getClass());
128→        synchronized (position) {
129→            if (handler == null) {
130→                result = QueryResult.forUnknownQueryType(query, store);
131→            } else if (context == null || !isPermitted(position, positionBound, context.taskId().partition())) {
132→                result = QueryResult.notUpToBound(
133→                    position,
134→                    positionBound,
135→                    context == null ? null : context.taskId().partition()
136→                );
137→            } else {
138→                result = (QueryResult<R>) handler.apply(
139→                    query,
140→                    positionBound,
141→                    config,
142→                    store
143→                );
144→            }
145→            if (config.isCollectExecutionInfo()) {
146→                result.addExecutionInfo(
147→                    "Handled in " + store.getClass() + " in " + (System.nanoTime() - start) + "ns"
148→                );
149→            }
150→            result.setPosition(position.copy());
151→        }
152→        return result;
153→    }
154→
155→    public static void updatePosition(
156→        final Position position,
157→        final StateStoreContext stateStoreContext) {
158→
159→        if (stateStoreContext != null && stateStoreContext.recordMetadata().isPresent()) {
160→            final RecordMetadata meta = stateStoreContext.recordMetadata().get();
161→            if (meta.topic() != null) {
162→                position.withComponent(meta.topic(), meta.partition(), meta.offset());
163→            }
164→        }
165→    }
166→
167→    public static boolean isPermitted(
168→        final Position position,
169→        final PositionBound positionBound,
170→        final int partition
171→    ) {
172→        final Position bound = positionBound.position();
173→        for (final String topic : bound.getTopics()) {
174→            final Map<Integer, Long> partitionBounds = bound.getPartitionPositions(topic);
175→            final Map<Integer, Long> seenPartitionPositions = position.getPartitionPositions(topic);
176→            if (!partitionBounds.containsKey(partition)) {
177→                // this topic isn't bounded for our partition, so just skip over it.
178→            } else {
179→                if (!seenPartitionPositions.containsKey(partition)) {
180→                    // we haven't seen a partition that we have a bound for
181→                    return false;
182→                } else if (seenPartitionPositions.get(partition) < partitionBounds.get(partition)) {
183→                    // our current position is behind the bound
184→                    return false;
185→                }
186→            }
187→        }
188→        return true;
189→    }
190→
191→    @SuppressWarnings("unchecked")
192→    private static <R> QueryResult<R> runRangeQuery(
193→        final Query<R> query,
194→        final PositionBound positionBound,
195→        final QueryConfig config,
196→        final StateStore store
197→    ) {
198→        if (!(store instanceof KeyValueStore)) {
199→            return QueryResult.forUnknownQueryType(query, store);
200→        }
201→        final KeyValueStore<Bytes, byte[]> kvStore = (KeyValueStore<Bytes, byte[]>) store;
202→        final RangeQuery<Bytes, byte[]> rangeQuery = (RangeQuery<Bytes, byte[]>) query;
203→        final Optional<Bytes> lowerRange = rangeQuery.getLowerBound();
204→        final Optional<Bytes> upperRange = rangeQuery.getUpperBound();
205→        final ResultOrder order = rangeQuery.resultOrder();
206→        final KeyValueIterator<Bytes, byte[]> iterator;
207→        try {
208→            if (lowerRange.isEmpty() && upperRange.isEmpty() && !order.equals(ResultOrder.DESCENDING)) {
209→                iterator = kvStore.all();
210→            } else if (!order.equals(ResultOrder.DESCENDING)) {
211→                iterator = kvStore.range(lowerRange.orElse(null), upperRange.orElse(null));
212→            } else if (lowerRange.isEmpty() && upperRange.isEmpty()) {
213→                iterator = kvStore.reverseAll();
214→            } else {
215→                iterator = kvStore.reverseRange(lowerRange.orElse(null), upperRange.orElse(null));
216→            }
217→            final R result = (R) iterator;
218→            return QueryResult.forResult(result);
219→        } catch (final Exception e) {
220→            final String message = parseStoreException(e, store, query);
221→            return QueryResult.forFailure(
222→                FailureReason.STORE_EXCEPTION,
223→                message
224→            );
225→        }
226→    }
227→
228→    @SuppressWarnings("unchecked")
229→    private static <R> QueryResult<R> runKeyQuery(final Query<R> query,
230→                                                  final PositionBound positionBound,
231→                                                  final QueryConfig config,
232→                                                  final StateStore store) {
233→
234→        if (store instanceof KeyValueStore) {
235→            final KeyQuery<Bytes, byte[]> rawKeyQuery = (KeyQuery<Bytes, byte[]>) query;
236→            final KeyValueStore<Bytes, byte[]> keyValueStore =
237→                (KeyValueStore<Bytes, byte[]>) store;
238→            try {
239→                final byte[] bytes = keyValueStore.get(rawKeyQuery.getKey());
240→                return (QueryResult<R>) QueryResult.forResult(bytes);
241→            } catch (final Exception e) {
242→                final String message = parseStoreException(e, store, query);
243→                return QueryResult.forFailure(
244→                    FailureReason.STORE_EXCEPTION,
245→                    message
246→                );
247→            }
248→        } else {
249→            return QueryResult.forUnknownQueryType(query, store);
250→        }
251→    }
252→
253→    @SuppressWarnings("unchecked")
254→    private static <R> QueryResult<R> runWindowKeyQuery(final Query<R> query,
255→                                                        final PositionBound positionBound,
256→                                                        final QueryConfig config,
257→                                                        final StateStore store) {
258→        if (store instanceof WindowStore) {
259→            final WindowKeyQuery<Bytes, byte[]> windowKeyQuery =
260→                (WindowKeyQuery<Bytes, byte[]>) query;
261→            final WindowStore<Bytes, byte[]> windowStore = (WindowStore<Bytes, byte[]>) store;
262→            try {
263→                if (windowKeyQuery.getTimeFrom().isPresent() && windowKeyQuery.getTimeTo().isPresent()) {
264→                    final WindowStoreIterator<byte[]> iterator = windowStore.fetch(
265→                        windowKeyQuery.getKey(),
266→                        windowKeyQuery.getTimeFrom().get(),
267→                        windowKeyQuery.getTimeTo().get()
268→                    );
269→                    return (QueryResult<R>) QueryResult.forResult(iterator);
270→                } else {
271→                    return QueryResult.forFailure(
272→                        FailureReason.UNKNOWN_QUERY_TYPE,
273→                        "This store (" + store.getClass() + ") doesn't know how to"
274→                            + " execute the given query (" + query + ") because it only supports"
275→                            + " closed-range queries."
276→                            + " Contact the store maintainer if you need support"
277→                            + " for a new query type."
278→                    );
279→                }
280→            } catch (final Exception e) {
281→                final String message = parseStoreException(e, store, query);
282→                return QueryResult.forFailure(FailureReason.STORE_EXCEPTION, message);
283→            }
284→        } else {
285→            return QueryResult.forUnknownQueryType(query, store);
286→        }
287→    }
