289→    @SuppressWarnings("unchecked")
290→    private static <R> QueryResult<R> runWindowRangeQuery(final Query<R> query,
291→                                                          final PositionBound positionBound,
292→                                                          final QueryConfig config,
293→                                                          final StateStore store) {
294→        if (store instanceof WindowStore) {
295→            final WindowRangeQuery<Bytes, byte[]> windowRangeQuery =
296→                (WindowRangeQuery<Bytes, byte[]>) query;
297→            final WindowStore<Bytes, byte[]> windowStore = (WindowStore<Bytes, byte[]>) store;
298→            try {
299→                // There's no store API for open time ranges
300→                if (windowRangeQuery.getTimeFrom().isPresent() && windowRangeQuery.getTimeTo().isPresent()) {
301→                    final KeyValueIterator<Windowed<Bytes>, byte[]> iterator =
302→                        windowStore.fetchAll(
303→                            windowRangeQuery.getTimeFrom().get(),
304→                            windowRangeQuery.getTimeTo().get()
305→                        );
306→                    return (QueryResult<R>) QueryResult.forResult(iterator);
307→                } else {
308→                    return QueryResult.forFailure(
309→                        FailureReason.UNKNOWN_QUERY_TYPE,
310→                        "This store (" + store.getClass() + ") doesn't know how to"
311→                            + " execute the given query (" + query + ") because"
312→                            + " WindowStores only supports WindowRangeQuery.withWindowStartRange."
313→                            + " Contact the store maintainer if you need support"
314→                            + " for a new query type."
315→                    );
316→                }
317→            } catch (final Exception e) {
318→                final String message = parseStoreException(e, store, query);
319→                return QueryResult.forFailure(
320→                    FailureReason.STORE_EXCEPTION,
321→                    message
322→                );
323→            }
324→        } else if (store instanceof SessionStore) {
325→            final WindowRangeQuery<Bytes, byte[]> windowRangeQuery =
326→                (WindowRangeQuery<Bytes, byte[]>) query;
327→            final SessionStore<Bytes, byte[]> sessionStore = (SessionStore<Bytes, byte[]>) store;
328→            try {
329→                if (windowRangeQuery.getKey().isPresent()) {
330→                    final KeyValueIterator<Windowed<Bytes>, byte[]> iterator = sessionStore.fetch(
331→                        windowRangeQuery.getKey().get());
332→                    return (QueryResult<R>) QueryResult.forResult(iterator);
333→                } else {
334→                    return QueryResult.forFailure(
335→                        FailureReason.UNKNOWN_QUERY_TYPE,
336→                        "This store (" + store.getClass() + ") doesn't know how to"
337→                            + " execute the given query (" + query + ") because"
338→                            + " SessionStores only support WindowRangeQuery.withKey."
339→                            + " Contact the store maintainer if you need support"
340→                            + " for a new query type."
341→                    );
342→                }
343→            } catch (final Exception e) {
344→                final String message = parseStoreException(e, store, query);
345→                return QueryResult.forFailure(
346→                    FailureReason.STORE_EXCEPTION,
347→                    message
348→                );
349→            }
350→        } else {
351→            return QueryResult.forUnknownQueryType(query, store);
352→        }
353→    }
