355→    @SuppressWarnings("unchecked")
356→    private static <R> QueryResult<R> runVersionedKeyQuery(final Query<R> query,
357→                                                           final PositionBound positionBound,
358→                                                           final QueryConfig config,
359→                                                           final StateStore store) {
360→        if (store instanceof VersionedKeyValueStore) {
361→            final VersionedKeyValueStore<Bytes, byte[]> versionedKeyValueStore =
362→                (VersionedKeyValueStore<Bytes, byte[]>) store;
363→            final VersionedKeyQuery<Bytes, byte[]> rawKeyQuery =
364→                (VersionedKeyQuery<Bytes, byte[]>) query;
365→            try {
366→                final VersionedRecord<byte[]> bytes;
367→                if (((VersionedKeyQuery<?, ?>) query).asOfTimestamp().isPresent()) {
368→                    bytes = versionedKeyValueStore.get(rawKeyQuery.key(),
369→                        ((VersionedKeyQuery<?, ?>) query).asOfTimestamp().get().toEpochMilli());
370→                } else {
371→                    bytes = versionedKeyValueStore.get(rawKeyQuery.key());
372→                }
373→                return (QueryResult<R>) QueryResult.forResult(bytes);
374→            } catch (final Exception e) {
375→                final String message = parseStoreException(e, store, query);
376→                return QueryResult.forFailure(
377→                    FailureReason.STORE_EXCEPTION,
378→                    message
379→                );
380→            }
381→
382→        } else {
383→            return QueryResult.forUnknownQueryType(query, store);
384→        }
385→    }
