387→    @SuppressWarnings("unchecked")
388→    private static <R> QueryResult<R> runMultiVersionedKeyQuery(final Query<R> query,
389→                                                                final PositionBound positionBound,
390→                                                                final QueryConfig config,
391→                                                                final StateStore store) {
392→
393→        if (store instanceof VersionedKeyValueStore) {
394→            final RocksDBVersionedStore rocksDBVersionedStore = (RocksDBVersionedStore) store;
395→            final MultiVersionedKeyQuery<Bytes, byte[]> rawKeyQuery = (MultiVersionedKeyQuery<Bytes, byte[]>) query;
396→            try {
397→                final VersionedRecordIterator<byte[]> segmentIterator =
398→                        rocksDBVersionedStore.get(rawKeyQuery.key(),
399→                                                  rawKeyQuery.fromTime().get().toEpochMilli(),
400→                                                  rawKeyQuery.toTime().get().toEpochMilli(),
401→                                                  rawKeyQuery.resultOrder());
402→                return (QueryResult<R>) QueryResult.forResult(segmentIterator);
403→            } catch (final Exception e) {
404→                final String message = parseStoreException(e, store, query);
405→                return QueryResult.forFailure(FailureReason.STORE_EXCEPTION, message);
406→            }
407→        } else {
408→            return QueryResult.forUnknownQueryType(query, store);
409→        }
410→    }
