412→    @SuppressWarnings({"unchecked", "rawtypes"})
413→    public static <V> Function<byte[], V> deserializeValue(final StateSerdes<?, V> serdes, final StateStore wrapped) {
414→        final Serde<V> valueSerde = serdes.valueSerde();
415→        final boolean timestamped = WrappedStateStore.isTimestamped(wrapped) || isAdapter(wrapped);
416→        final Deserializer<V> deserializer;
417→        if (!timestamped && valueSerde instanceof ValueAndTimestampSerde) {
418→            final ValueAndTimestampDeserializer valueAndTimestampDeserializer =
419→                (ValueAndTimestampDeserializer) ((ValueAndTimestampSerde) valueSerde).deserializer();
420→            deserializer = (Deserializer<V>) valueAndTimestampDeserializer.valueDeserializer;
421→        } else {
422→            deserializer = valueSerde.deserializer();
423→        }
424→        return byteArray -> deserializer.deserialize(serdes.topic(), byteArray);
425→    }
426→
427→    public static boolean isAdapter(final StateStore stateStore) {
428→        if (stateStore instanceof KeyValueToTimestampedKeyValueByteStoreAdapter) {
429→            return true;
430→        } else if (stateStore instanceof WrappedStateStore) {
431→            return isAdapter(((WrappedStateStore) stateStore).wrapped());
432→        } else {
433→            return false;
434→        }
435→    }
436→
437→    @SuppressWarnings({"unchecked", "rawtypes"})
438→    public static <V> Function<VersionedRecord<byte[]>, VersionedRecord<V>> deserializeValue(final StateSerdes<?, V> serdes) {
439→        final Serde<V> valueSerde = serdes.valueSerde();
440→        final Deserializer<V> deserializer = valueSerde.deserializer();
441→        return rawVersionedRecord -> rawVersionedRecord.validTo().isPresent() ? new VersionedRecord<>(deserializer.deserialize(serdes.topic(), rawVersionedRecord.value()),
442→                                                                                                      rawVersionedRecord.timestamp(),
443→                                                                                                      rawVersionedRecord.validTo().get())
444→                                                                              : new VersionedRecord<>(deserializer.deserialize(serdes.topic(), rawVersionedRecord.value()),
445→                                                                                                      rawVersionedRecord.timestamp());
446→    }
447→
448→    public static <V> VersionedRecord<V> deserializeVersionedRecord(final StateSerdes<?, V> serdes, final VersionedRecord<byte[]> rawVersionedRecord) {
449→        final Deserializer<V> valueDeserializer = serdes.valueDeserializer();
450→        final V value = valueDeserializer.deserialize(serdes.topic(), rawVersionedRecord.value());
451→        return rawVersionedRecord.validTo().isPresent() ? new VersionedRecord<>(value, rawVersionedRecord.timestamp(), rawVersionedRecord.validTo().get())
452→                                                        : new VersionedRecord<>(value, rawVersionedRecord.timestamp());
453→    }
