455→    public static void checkpointPosition(final OffsetCheckpoint checkpointFile, final Position position) {
456→        try {
457→            checkpointFile.write(positionToTopicPartitionMap(position));
458→        } catch (final IOException e) {
459→            throw new ProcessorStateException("Error writing checkpoint file", e);
460→        }
461→    }
462→
463→    public static Position readPositionFromCheckpoint(final OffsetCheckpoint checkpointFile) {
464→        try {
465→            return topicPartitionMapToPosition(checkpointFile.read());
466→        } catch (final IOException e) {
467→            throw new ProcessorStateException("Error reading checkpoint file", e);
468→        }
469→    }
470→
471→    private static Map<TopicPartition, Long> positionToTopicPartitionMap(final Position position) {
472→        final Map<TopicPartition, Long> topicPartitions = new HashMap<>();
473→        final Set<String> topics = position.getTopics();
474→        for (final String t : topics) {
475→            final Map<Integer, Long> partitions = position.getPartitionPositions(t);
476→            for (final Entry<Integer, Long> e : partitions.entrySet()) {
477→                final TopicPartition tp = new TopicPartition(t, e.getKey());
478→                topicPartitions.put(tp, e.getValue());
479→            }
480→        }
481→        return topicPartitions;
482→    }
483→
484→    private static Position topicPartitionMapToPosition(final Map<TopicPartition, Long> topicPartitions) {
485→        final Map<String, Map<Integer, Long>> pos = new HashMap<>();
486→        for (final Entry<TopicPartition, Long> e : topicPartitions.entrySet()) {
487→            pos
488→                .computeIfAbsent(e.getKey().topic(), t -> new HashMap<>())
489→                .put(e.getKey().partition(), e.getValue());
490→        }
491→        return Position.fromMap(pos);
492→    }
493→
494→    private static <R> String parseStoreException(final Exception e, final StateStore store, final Query<R> query) {
495→        final StringWriter stringWriter = new StringWriter();
496→        final PrintWriter printWriter = new PrintWriter(stringWriter);
497→        printWriter.println(
498→            store.getClass() + " failed to handle query " + query + ":");
499→        e.printStackTrace(printWriter);
500→        printWriter.flush();
501→        return stringWriter.toString();
502→    }
503→}
