17→package org.apache.kafka.streams.state.internals;
18→
19→import org.apache.kafka.common.utils.AbstractIterator;
20→import org.apache.kafka.common.utils.Bytes;
21→import org.apache.kafka.streams.KeyValue;
22→import org.apache.kafka.streams.errors.InvalidStateStoreException;
23→
24→import org.rocksdb.RocksIterator;
25→
26→import java.util.NoSuchElementException;
27→import java.util.function.Consumer;
28→
29→class RocksDbIterator extends AbstractIterator<KeyValue<Bytes, byte[]>> implements ManagedKeyValueIterator<Bytes, byte[]> {
30→
31→    private final String storeName;
32→    private final RocksIterator iter;
33→    private final Consumer<RocksIterator> advanceIterator;
34→
35→    private volatile boolean open = true;
36→
37→    private KeyValue<Bytes, byte[]> next;
38→    private Runnable closeCallback = null;
39→
40→    RocksDbIterator(final String storeName,
41→                    final RocksIterator iter,
42→                    final boolean forward) {
43→        this.storeName = storeName;
44→        this.iter = iter;
45→        this.advanceIterator = forward ? RocksIterator::next : RocksIterator::prev;
46→    }
47→
48→    @Override
49→    public synchronized boolean hasNext() {
50→        if (!open) {
51→            throw new InvalidStateStoreException(String.format("RocksDB iterator for store %s has closed", storeName));
52→        }
53→        return super.hasNext();
54→    }
55→
56→    @Override
57→    protected KeyValue<Bytes, byte[]> makeNext() {
58→        if (!iter.isValid()) {
59→            return allDone();
60→        } else {
61→            next = getKeyValue();
62→            advanceIterator.accept(iter);
63→            return next;
64→        }
65→    }
66→
67→    private KeyValue<Bytes, byte[]> getKeyValue() {
68→        return new KeyValue<>(new Bytes(iter.key()), iter.value());
69→    }
70→
71→    @Override
72→    public synchronized void close() {
73→        if (closeCallback == null) {
74→            throw new IllegalStateException("RocksDbIterator expects close callback to be set immediately upon creation");
75→        }
76→        closeCallback.run();
77→
78→        iter.close();
79→        open = false;
80→    }
81→
82→    @Override
83→    public Bytes peekNextKey() {
84→        if (!hasNext()) {
85→            throw new NoSuchElementException();
86→        }
87→        return next.key;
88→    }
89→
90→    @Override
91→    public synchronized void onClose(final Runnable closeCallback) {
92→        this.closeCallback = closeCallback;
93→    }
94→}
