 61→class TimeOrderedCachingWindowStore
 62→    extends WrappedStateStore<WindowStore<Bytes, byte[]>, byte[], byte[]>
 63→    implements WindowStore<Bytes, byte[]>, CachedStateStore<byte[], byte[]> {
 64→
 65→    private static final Logger LOG = LoggerFactory.getLogger(TimeOrderedCachingWindowStore.class);
 66→
 67→    private final long windowSize;
 68→    private final SegmentedCacheFunction baseKeyCacheFunction;
 69→    private final SegmentedCacheFunction indexKeyCacheFunction;
 70→    private final TimeFirstWindowKeySchema baseKeySchema = new TimeFirstWindowKeySchema();
 71→    private final KeyFirstWindowKeySchema indexKeySchema = new KeyFirstWindowKeySchema();
 72→
 73→    private String cacheName;
 74→    private boolean hasIndex;
 75→    private boolean sendOldValues;
 76→    private InternalProcessorContext<?, ?> internalContext;
 77→    private StateSerdes<Bytes, byte[]> bytesSerdes;
 78→    private CacheFlushListener<byte[], byte[]> flushListener;
 79→
 80→    private final AtomicLong maxObservedTimestamp;
 81→
 82→    TimeOrderedCachingWindowStore(final WindowStore<Bytes, byte[]> underlying,
 83→                                  final long windowSize,
 84→                                  final long segmentInterval) {
 85→        super(underlying);
 86→        this.windowSize = windowSize;
 87→        this.baseKeyCacheFunction = new SegmentedCacheFunction(baseKeySchema, segmentInterval);
 88→        this.indexKeyCacheFunction = new SegmentedCacheFunction(indexKeySchema, segmentInterval);
 89→        this.maxObservedTimestamp = new AtomicLong(RecordQueue.UNKNOWN);
 90→        enforceWrappedStore(underlying);
 91→    }
 92→
 93→    private void enforceWrappedStore(final WindowStore<Bytes, byte[]> underlying) {
 94→        final RocksDBTimeOrderedWindowStore timeOrderedWindowStore = getWrappedStore(underlying);
 95→        if (timeOrderedWindowStore == null) {
 96→            throw new IllegalArgumentException("TimeOrderedCachingWindowStore only supports RocksDBTimeOrderedWindowStore backed store");
 97→        }
 98→
 99→        hasIndex = timeOrderedWindowStore.hasIndex();
100→    }
101→
102→    @SuppressWarnings("unchecked")
103→    private RocksDBTimeOrderedWindowStore getWrappedStore(final StateStore wrapped) {
104→        if (wrapped instanceof RocksDBTimeOrderedWindowStore) {
105→            return (RocksDBTimeOrderedWindowStore) wrapped;
106→        }
107→        if (wrapped instanceof WrappedStateStore) {
108→            return getWrappedStore(((WrappedStateStore<?, Bytes, byte[]>) wrapped).wrapped());
109→        }
110→        return null;
111→    }
112→
113→    @Override
114→    public void init(final StateStoreContext stateStoreContext, final StateStore root) {
115→        final String prefix = StreamsConfig.InternalConfig.getString(
116→            stateStoreContext.appConfigs(),
117→            StreamsConfig.InternalConfig.TOPIC_PREFIX_ALTERNATIVE,
118→            stateStoreContext.applicationId()
119→        );
120→        internalContext = asInternalProcessorContext(stateStoreContext);
121→        final String topic = ProcessorStateManager.storeChangelogTopic(prefix, name(),  stateStoreContext.taskId().topologyName());
122→
123→        bytesSerdes = new StateSerdes<>(
124→            topic,
125→            Serdes.Bytes(),
126→            Serdes.ByteArray());
127→        cacheName = stateStoreContext.taskId() + "-" + name();
128→
129→        internalContext.registerCacheFlushListener(cacheName, entries -> putAndMaybeForward(entries, internalContext));
130→        super.init(stateStoreContext, root);
131→    }
132→
133→    private void putAndMaybeForward(final List<DirtyEntry> entries,
134→                                    final InternalProcessorContext<?, ?> context) {
135→
136→        // Track what base key or index key we already processed so don't reprocess
137→        final Set<Bytes> processedBasedKey = new HashSet<>();
138→
139→        for (final ThreadCache.DirtyEntry entry : entries) {
140→            final byte[] binaryWindowKey = baseKeyCacheFunction.key(entry.key()).get();
141→            final boolean isBaseKey = PrefixedWindowKeySchemas.isTimeFirstSchemaKey(
142→                binaryWindowKey);
143→
144→            final DirtyEntry finalEntry;
145→            if (!isBaseKey) {
146→                final Bytes baseKey = indexKeyToBaseKey(Bytes.wrap(binaryWindowKey));
147→                if (hasIndex && processedBasedKey.contains(baseKey)) {
148→                    // Processed in base
149→                    continue;
150→                }
151→
152→                final Bytes cachedBaseKey = baseKeyCacheFunction.cacheKey(baseKey);
153→                final LRUCacheEntry value = context.cache().get(cacheName, cachedBaseKey);
154→                // Base key value is already evicted, which should be handled already
155→                if (value == null) {
156→                    continue;
157→                }
158→
159→                finalEntry = new DirtyEntry(entry.key(), value.value(), value);
160→
161→                if (hasIndex) {
162→                    processedBasedKey.add(baseKey);
163→                }
164→            } else {
165→                final Bytes baseKey = Bytes.wrap(binaryWindowKey);
166→                if (hasIndex && processedBasedKey.contains(baseKey)) {
167→                    // Processed in index
168→                    continue;
169→                }
170→                finalEntry = entry;
171→                if (hasIndex) {
172→                    processedBasedKey.add(Bytes.wrap(binaryWindowKey));
173→                }
174→            }
175→
176→            final Windowed<Bytes> windowedKeyBytes;
177→            if (isBaseKey) {
178→                windowedKeyBytes = TimeFirstWindowKeySchema.fromStoreBytesKey(binaryWindowKey,
179→                    windowSize);
180→            } else {
181→                windowedKeyBytes = KeyFirstWindowKeySchema.fromStoreBytesKey(binaryWindowKey,
182→                    windowSize);
183→            }
184→
185→            final long windowStartTimestamp = windowedKeyBytes.window().start();
186→            final Bytes binaryKey = windowedKeyBytes.key();
187→
188→            putAndMaybeForward(context, finalEntry, binaryKey, windowStartTimestamp);
189→        }
190→    }
191→
192→    private void putAndMaybeForward(final InternalProcessorContext<?, ?> context,
193→                                    final DirtyEntry finalEntry,
194→                                    final Bytes binaryKey,
195→                                    final long windowStartTimestamp) {
196→        if (flushListener != null) {
197→            final byte[] rawNewValue = finalEntry.newValue();
198→            final byte[] rawOldValue = rawNewValue == null || sendOldValues ?
199→                wrapped().fetch(binaryKey, windowStartTimestamp) : null;
200→
201→            // this is an optimization: if this key did not exist in underlying store and also not in the cache,
202→            // we can skip flushing to downstream as well as writing to underlying store
203→            if (rawNewValue != null || rawOldValue != null) {
204→                // we need to get the old values if needed, and then put to store, and then flush
205→                final ProcessorRecordContext current = context.recordContext();
206→                try {
207→                    context.setRecordContext(finalEntry.entry().context());
208→                    wrapped().put(binaryKey, finalEntry.newValue(), windowStartTimestamp);
209→
210→                    flushListener.apply(
211→                        new Record<>(
212→                            WindowKeySchema.toStoreKeyBinary(binaryKey,
213→                                    windowStartTimestamp, 0)
214→                                .get(),
215→                            new Change<>(rawNewValue, sendOldValues ? rawOldValue : null),
216→                            finalEntry.entry().context().timestamp(),
217→                            finalEntry.entry().context().headers()));
218→                } finally {
219→                    context.setRecordContext(current);
220→                }
221→            }
