249→    @Override
250→    public synchronized void put(final Bytes key,
251→                                 final byte[] value,
252→                                 final long windowStartTimestamp) {
253→        // since this function may not access the underlying inner store, we need to validate
254→        // if store is open outside as well.
255→        validateStoreOpen();
256→
257→        final Bytes baseKeyBytes = TimeFirstWindowKeySchema.toStoreKeyBinary(key, windowStartTimestamp, 0);
258→        final LRUCacheEntry entry =
259→            new LRUCacheEntry(
260→                value,
261→                internalContext.recordContext().headers(),
262→                true,
263→                internalContext.recordContext().offset(),
264→                internalContext.recordContext().timestamp(),
265→                internalContext.recordContext().partition(),
266→                internalContext.recordContext().topic(),
267→                internalContext.recordContext().sourceRawKey(),
268→                internalContext.recordContext().sourceRawValue()
269→            );
270→
271→        // Put to index first so that base can be evicted later
272→        if (hasIndex) {
273→            // Important: put base key first to avoid the situation that if we put index first,
274→            // it could be evicted when we are putting base key. In that case, base key is not yet
275→            // in cache so we can't store key/value to store when index is evicted. Then if we fetch
276→            // using index, we can't find it in either store or cache
277→            internalContext.cache().put(cacheName, baseKeyCacheFunction.cacheKey(baseKeyBytes), entry);
278→            final LRUCacheEntry emptyEntry =
279→                new LRUCacheEntry(
280→                    new byte[0],
281→                    new RecordHeaders(),
282→                    true,
283→                    internalContext.recordContext().offset(),
284→                    internalContext.recordContext().timestamp(),
285→                    internalContext.recordContext().partition(),
286→                    "",
287→                    internalContext.recordContext().sourceRawKey(),
288→                    internalContext.recordContext().sourceRawValue()
289→                );
290→            final Bytes indexKey = KeyFirstWindowKeySchema.toStoreKeyBinary(key, windowStartTimestamp, 0);
291→            internalContext.cache().put(cacheName, indexKeyCacheFunction.cacheKey(indexKey), emptyEntry);
292→        } else {
293→            internalContext.cache().put(cacheName, baseKeyCacheFunction.cacheKey(baseKeyBytes), entry);
294→        }
295→        maxObservedTimestamp.set(Math.max(windowStartTimestamp, maxObservedTimestamp.get()));
296→    }
