Lines: 138-148 and 168-174

public synchronized void put(final Bytes key, final byte[] value) {  // Lock 1: MemoryLRUCache (this)
    Objects.requireNonNull(key);
    synchronized (position) {  // Lock 2: Position object
        if (value == null) {
            delete(key);
        } else {
            this.map.put(key, value);
        }
        StoreQueryUtils.updatePosition(position, context);
    }
}

public synchronized byte[] delete(final Bytes key) {  // Lock 1: MemoryLRUCache (this)
    Objects.requireNonNull(key);
